#!/bin/bash
set -euo pipefail
FILE=/var/www/html_api/api_cdr.php
BK="${FILE}.bak.$(date +%Y%m%d%H%M)"
cp "$FILE" "$BK"
TMP="${FILE}.new"
cat > "$TMP" << 'HEADER'
<?php
/**
 * API CDR Issabel → Suite (issabel-calls Edge Function)
 * Ruta en servidor: /var/www/html_api/api_cdr.php
 *
 * Tras copiar: conserva $api_token_valido y credenciales DB del fichero anterior.
 *
 * Endpoints:
 *   GET ?limit=500&from=2026-06-01&to=2026-06-08        → JSON listado CDR
 *   GET ?format=wav&uniqueid=1780593561.132271          → audio WAV (por uniqueid CDR)
 *   GET ?file=rg-100-662584162-20260608-145040-....wav  → audio WAV (por nombre en monitor)
 */

declare(strict_types=1);

// --- Mantener estos valores del api_cdr.php actual en Issabel ---
HEADER
grep -E '^\$(api_token_valido|db_user|db_pass|db_name)' "$BK" >> "$TMP"
echo '// -----------------------------------------------------------------' >> "$TMP"
base64 -d >> "$TMP" << 'END_BODY'

END_BODY
php -l "$TMP" >/dev/null
mv "$TMP" "$FILE"
chmod 644 "$FILE"
echo "OK api_cdr.php actualizado (backup: $BK)"
TOKEN=$(grep '^\$api_token_valido' "$FILE" | sed -E "s/^[^']*'([^']*)'.*/\1/")
CALLUID=$(curl -s -H "Authorization: Bearer $TOKEN" "http://127.0.0.1:8888/api_cdr.php?from=2026-06-08&limit=20" | grep -oE '[0-9]+\.[0-9]+' | head -1)
if [ -n "$CALLUID" ]; then
  CODE=$(curl -s -o /dev/null -w '%{http_code}' -H "Authorization: Bearer $TOKEN" "http://127.0.0.1:8888/api_cdr.php?format=wav&uniqueid=$CALLUID")
  echo "Smoke test wav uniqueid=$CALLUID -> HTTP $CODE"
fi
